const body = $('Telegram Webhook').first().json.body || $('Telegram Webhook').first().json;
const sd = $getWorkflowStaticData('global');

let action = '', postId = '', batchId = '', messageText = '', chatId = '', userId = '';

// Handle callback_query (button click)
if (body.callback_query) {
  const cb = body.callback_query;
  const data = cb.data || '';
  const parts = data.split('|');
  action = parts[0] || '';
  batchId = parts[1] || '';
  chatId = String(cb.message?.chat?.id || '');
  userId = String(cb.from?.id || '');
  sd.chatId = chatId;
  sd.batchId = batchId;
}
// Handle text message (reply to bot)
else if (body.message && body.message.text) {
  messageText = body.message.text.trim();
  chatId = String(body.message.chat?.id || sd.chatId || '');
  userId = String(body.message.from?.id || '');

  const upper = messageText.toUpperCase();
  if (upper.startsWith('IMAGE ')) { action = 'process_image'; postId = messageText.split(/\s+/)[1] || ''; }
  else if (upper.startsWith('TEXT ')) { action = 'process_text'; postId = messageText.split(/\s+/)[1] || ''; }
  else if (upper.startsWith('HOOK ')) { action = 'process_text'; postId = messageText.split(/\s+/)[1] || ''; }
  else if (upper.startsWith('REGEN ')) { action = 'process_regen'; postId = messageText.split(/\s+/)[1] || ''; }
  else { action = 'unknown'; }
}

const cfg = $('Read Config').first().json;
const token = cfg.telegramBotToken || '';

return [{ json: { action, postId, batchId, messageText, chatId, userId, token, rawBody: body } }];

const data = $('Parse Incoming').first().json;
const token = data.token;
const chatId = data.chatId;
const batchId = data.batchId;

// Send confirmation
await $helpers.httpRequest({
  method: 'POST',
  url: `https://api.telegram.org/bot${token}/sendMessage`,
  body: {
    chat_id: chatId,
    text: `✅ *ALL CONTENT APPROVED!*\n\nBatch: \`${batchId}\`\n\n📅 Publishing will proceed per schedule.\n🤖 The publishing engine will auto-publish each post at its scheduled time.\n\nGreat work! 🎉`,
    parse_mode: 'Markdown'
  },
  headers: { 'Content-Type': 'application/json' }
});

return [{ json: { action: 'approve', batchId, chatId } }];

const cal = $input.all().map(i => i.json);
const now = new Date().toISOString();
const results = [];

for (const row of cal) {
  if (row.Status === 'visuals_created') {
    results.push({
      json: {
        PostID: row.PostID,
        Status: 'approved',
        ApprovalStatus: 'approved',
        ApprovedAt: now
      }
    });
  }
}

return results.length > 0 ? results : [{ json: { skip: true } }];

const data = $('Parse Incoming').first().json;
await $helpers.httpRequest({
  method: 'POST',
  url: `https://api.telegram.org/bot${data.token}/sendMessage`,
  body: {
    chat_id: data.chatId,
    text: '🖼️ *Change Image*\n\nSend the new image in this format:\n\n`IMAGE PostID ImageURL`\n\nExample:\n`IMAGE IMG-20260323-001 https://example.com/new-photo.jpg`\n\nYou can find the Post ID in the content preview above.',
    parse_mode: 'Markdown'
  },
  headers: { 'Content-Type': 'application/json' }
});
return [{ json: { asked: 'image', chatId: data.chatId } }];

const data = $('Parse Incoming').first().json;
await $helpers.httpRequest({
  method: 'POST',
  url: `https://api.telegram.org/bot${data.token}/sendMessage`,
  body: {
    chat_id: data.chatId,
    text: '✏️ *Change Text*\n\nSend the new text in one of these formats:\n\n`TEXT PostID Your new caption here`\n`HOOK PostID Your new hook here`\n\nExamples:\n`TEXT IMG-20260323-001 New caption text for this post`\n`HOOK CAR-20260324-001 New hook that grabs attention`',
    parse_mode: 'Markdown'
  },
  headers: { 'Content-Type': 'application/json' }
});
return [{ json: { asked: 'text', chatId: data.chatId } }];

const data = $('Parse Incoming').first().json;
await $helpers.httpRequest({
  method: 'POST',
  url: `https://api.telegram.org/bot${data.token}/sendMessage`,
  body: {
    chat_id: data.chatId,
    text: '🔄 *Regenerate Content*\n\nSend the Post ID to regenerate:\n\n`REGEN PostID`\n\nExample:\n`REGEN IMG-20260323-001`\n\nThis will generate completely new content + visuals for that post.',
    parse_mode: 'Markdown'
  },
  headers: { 'Content-Type': 'application/json' }
});
return [{ json: { asked: 'regen', chatId: data.chatId } }];

const data = $('Parse Incoming').first().json;
const msg = data.messageText;
const parts = msg.split(/\s+/);
const postId = parts[1] || '';
const imageUrl = parts.slice(2).join(' ').trim();

if (!postId || !imageUrl) {
  await $helpers.httpRequest({
    method: 'POST', url: `https://api.telegram.org/bot${data.token}/sendMessage`,
    body: { chat_id: data.chatId, text: '❌ Invalid format. Use: `IMAGE PostID URL`', parse_mode: 'Markdown' },
    headers: { 'Content-Type': 'application/json' }
  });
  return [{ json: { error: true } }];
}

return [{ json: { postId, imageUrl, token: data.token, chatId: data.chatId } }];

const imgData = $('Process Image Change').first().json;
const postId = imgData.postId;
const newImageUrl = imgData.imageUrl;
const cal = $input.all().map(i => i.json);
const post = cal.find(r => r.PostID === postId);

if (!post) {
  await $helpers.httpRequest({
    method: 'POST', url: `https://api.telegram.org/bot${imgData.token}/sendMessage`,
    body: { chat_id: imgData.chatId, text: `❌ Post ID \`${postId}\` not found.`, parse_mode: 'Markdown' },
    headers: { 'Content-Type': 'application/json' }
  });
  return [{ json: { error: true } }];
}

const templateId = post['Preferred Template'] || '';
let templateUuid = '';
const match = templateId.match(/\(Id:([^)]+)\)/i) || templateId.match(/\(([a-f0-9\-]{36})\)/i);
if (match) templateUuid = match[1].trim();

const contentType = (post.ContentType || '').toLowerCase().replace(/\s+/g, '_');

return [{
  json: {
    postId,
    contentType,
    templateUuid,
    newImageUrl,
    hook: post.Hook || '',
    caption: post.Caption || '',
    topic: post.Topic || '',
    token: imgData.token,
    chatId: imgData.chatId,
    oldVisualUrl: post.Visual_URL || ''
  }
}];

const prep = $('Prepare Placid Rerender').first().json;
const render = $input.first().json;
const renderUrl = render.image_url || render.download_url || '';
const postId = prep.postId;
const token = prep.token;
const chatId = prep.chatId;

// Update calendar
// (We'll do this via a separate GSheets node)

// Send updated visual to Telegram
let msg = `🖼️ *Image Updated!*\n\n📌 Post: \`${postId}\`\n`;
if (renderUrl) {
  msg += `✅ New visual rendered successfully\n🔗 ${renderUrl}\n`;
} else {
  msg += `⚠️ Render may still be processing\n`;
}
msg += `\nClick below to approve or make more changes.`;

const keyboard = {
  inline_keyboard: [
    [
      { text: '✅ Approve & Schedule', callback_data: `approve_all|${postId}` },
      { text: '✏️ More Changes', callback_data: `change_image|${postId}` }
    ]
  ]
};

await $helpers.httpRequest({
  method: 'POST', url: `https://api.telegram.org/bot${token}/sendMessage`,
  body: { chat_id: chatId, text: msg, parse_mode: 'Markdown', reply_markup: keyboard },
  headers: { 'Content-Type': 'application/json' }
});

return [{ json: { postId, renderUrl, oldUrl: prep.oldVisualUrl, updated: true } }];

const data = $('Parse Incoming').first().json;
const msg = data.messageText;
const upper = msg.toUpperCase();
const isHook = upper.startsWith('HOOK ');
const parts = msg.split(/\s+/);
const postId = parts[1] || '';
const newText = parts.slice(2).join(' ').trim();
const field = isHook ? 'hook' : 'caption';

if (!postId || !newText) {
  await $helpers.httpRequest({
    method: 'POST', url: `https://api.telegram.org/bot${data.token}/sendMessage`,
    body: { chat_id: data.chatId, text: '❌ Invalid format. Use: `TEXT PostID your text` or `HOOK PostID your hook`', parse_mode: 'Markdown' },
    headers: { 'Content-Type': 'application/json' }
  });
  return [{ json: { error: true } }];
}

return [{ json: { postId, newText, field, token: data.token, chatId: data.chatId } }];

const textData = $('Process Text Change').first().json;
const aiResp = $input.first().json;

let refinedText = textData.newText; // fallback to original
try {
  refinedText = aiResp.choices[0].message.content.trim();
} catch(e) {}

return [{
  json: {
    postId: textData.postId,
    field: textData.field,
    originalText: textData.newText,
    refinedText,
    token: textData.token,
    chatId: textData.chatId
  }
}];

const textData = $('Parse Refined Text').first().json;
const cal = $input.all().map(i => i.json);
const post = cal.find(r => r.PostID === textData.postId);

if (!post) {
  await $helpers.httpRequest({
    method: 'POST', url: `https://api.telegram.org/bot${textData.token}/sendMessage`,
    body: { chat_id: textData.chatId, text: `❌ Post \`${textData.postId}\` not found.`, parse_mode: 'Markdown' },
    headers: { 'Content-Type': 'application/json' }
  });
  return [{ json: { error: true } }];
}

let templateUuid = '';
const tpl = post['Preferred Template'] || '';
const m = tpl.match(/\(Id:([^)]+)\)/i) || tpl.match(/\(([a-f0-9\-]{36})\)/i);
if (m) templateUuid = m[1].trim();

const newHook = textData.field === 'hook' ? textData.refinedText : (post.Hook || '');
const newCaption = textData.field === 'caption' ? textData.refinedText : (post.Caption || '');

return [{
  json: {
    postId: textData.postId,
    templateUuid,
    newHook,
    newCaption,
    field: textData.field,
    refinedText: textData.refinedText,
    originalText: textData.originalText,
    visualUrl: post.Visual_URL || '',
    token: textData.token,
    chatId: textData.chatId
  }
}];

const prep = $('Prepare Text Rerender').first().json;
const render = $input.first().json;
const renderUrl = render.image_url || render.download_url || '';

let msg = `✏️ *Text Updated + Re-rendered!*\n\n`;
msg += `📌 Post: \`${prep.postId}\`\n`;
msg += `📝 Field: ${prep.field}\n`;
msg += `🤖 AI refined: "${prep.refinedText.substring(0, 80)}${prep.refinedText.length > 80 ? '...' : ''}"\n`;
if (renderUrl) msg += `🖼️ New visual: ${renderUrl}\n`;
msg += `\nClick below to approve or make more changes.`;

const keyboard = {
  inline_keyboard: [
    [
      { text: '✅ Approve & Schedule', callback_data: `approve_all|${prep.postId}` },
      { text: '✏️ More Changes', callback_data: `change_text|${prep.postId}` }
    ]
  ]
};

await $helpers.httpRequest({
  method: 'POST', url: `https://api.telegram.org/bot${prep.token}/sendMessage`,
  body: { chat_id: prep.chatId, text: msg, parse_mode: 'Markdown', reply_markup: keyboard },
  headers: { 'Content-Type': 'application/json' }
});

return [{ json: { postId: prep.postId, renderUrl, field: prep.field, refinedText: prep.refinedText, originalCaption: prep.field === 'caption' ? prep.originalText : '', originalHook: prep.field === 'hook' ? prep.originalText : '' } }];

const data = $('Parse Incoming').first().json;
const parts = data.messageText.split(/\s+/);
const postId = parts[1] || '';

if (!postId) {
  await $helpers.httpRequest({
    method: 'POST', url: `https://api.telegram.org/bot${data.token}/sendMessage`,
    body: { chat_id: data.chatId, text: '❌ Invalid format. Use: `REGEN PostID`', parse_mode: 'Markdown' },
    headers: { 'Content-Type': 'application/json' }
  });
  return [{ json: { error: true } }];
}

return [{ json: { postId, token: data.token, chatId: data.chatId } }];

const regenData = $('Process Regen').first().json;
const cal = $input.all().map(i => i.json);
const post = cal.find(r => r.PostID === regenData.postId);

if (!post) {
  return [{ json: { error: true, postId: regenData.postId } }];
}

return [{
  json: {
    postId: regenData.postId,
    contentType: post.ContentType || 'single_image',
    pillar: post.Pillar || 'Education',
    day: post.Day || 'Monday',
    topic: post.Topic || '',
    templateUuid: '',
    token: regenData.token,
    chatId: regenData.chatId
  }
}];

const prep = $('Prepare Regen Prompt').first().json;
const aiResp = $input.first().json;

let newContent = {};
try {
  const text = aiResp.choices[0].message.content;
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) newContent = JSON.parse(jsonMatch[0]);
} catch(e) {
  newContent = { topic: 'Regenerated', hook: 'Fresh content', caption: 'New post content', hashtags: [], callToAction: 'Learn more' };
}

// Notify via Telegram
let msg = `🔄 *Content Regenerated!*\n\n`;
msg += `📌 Post: \`${prep.postId}\`\n`;
msg += `📝 New Topic: ${newContent.topic || 'N/A'}\n`;
msg += `🎣 New Hook: ${(newContent.hook || '').substring(0, 60)}\n`;
msg += `📊 Caption: ${(newContent.caption || '').split(/\s+/).length} words\n\n`;
msg += `⏳ Visual is being re-rendered...\nYou'll receive the updated preview shortly.`;

const keyboard = {
  inline_keyboard: [
    [
      { text: '✅ Approve & Schedule', callback_data: `approve_all|${prep.postId}` },
      { text: '🔄 Regenerate Again', callback_data: `regenerate|${prep.postId}` }
    ]
  ]
};

await $helpers.httpRequest({
  method: 'POST', url: `https://api.telegram.org/bot${prep.token}/sendMessage`,
  body: { chat_id: prep.chatId, text: msg, parse_mode: 'Markdown', reply_markup: keyboard },
  headers: { 'Content-Type': 'application/json' }
});

return [{
  json: {
    postId: prep.postId,
    newTopic: newContent.topic || '',
    newHook: newContent.hook || '',
    newCaption: newContent.caption || '',
    newHashtags: JSON.stringify(newContent.hashtags || []),
    newCTA: newContent.callToAction || '',
    newVisualDirection: newContent.visualDirection || ''
  }
}];
